class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator still works because we
        // configured HasDiscriminator<string>("Discriminator") in the model.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync I/O now throws — must use async APIs
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

